"import * as React from "react";

import { cn } from "../utils/cn";

export type DsButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & {
  variant?: "default" | "secondary" | "ghost" | "destructive" | "outline";
};

const variants: Record<NonNullable<DsButtonProps["variant"]>, string> = {
  default: "border-0 bg-primary text-primary-foreground hover:bg-[#c41300] active:bg-[#a00f00]",
  secondary: "border-0 bg-secondary text-secondary-foreground hover:bg-[#0f1f26] active:bg-[#0a141a]",
  ghost: "border border-accent bg-transparent text-accent hover:bg-[#e8f4ff] active:bg-[#d0eaff]",
  destructive: "border-0 bg-destructive text-destructive-foreground hover:bg-[#c41300] active:bg-[#a00f00]",
  outline: "border border-accent bg-transparent text-accent hover:bg-[#e8f4ff] active:bg-[#d0eaff]"
};

export const DsButton = React.forwardRef<HTMLButtonElement, DsButtonProps>(
  ({ className, variant = "default", type = "button", ...props }, ref) => (
    <button
      ref={ref}
      type={type}
      className={cn(
        "inline-flex min-h-12 min-w-12 items-center justify-center rounded-control px-6 py-3 text-base leading-6 font-semibold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
        variants[variant],
        className
      )}
      {...props}
    />
  )
);

DsButton.displayName = "DsButton";"

