"export default function SentinelFeaturesPage() {
  return (
    <SitePageFrame>
      <section className="hero-reveal bg-[#0A0A0C] border border-[rgba(255,255,255,0.05)] p-8 rounded-none shadow-sm">
        <p className="font-mono text-xs uppercase tracking-[0] text-muted-foreground">Sentinel</p>
        <h1 className="mt-2 text-[24px] leading-[30px] font-medium text-foreground md:text-[40px] md:leading-[48px]">Platform Features</h1>
      </section>
      <section className="bg-[#0A0A0C] border border-[rgba(255,255,255,0.05)] p-8 rounded-none">
        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
          {features.map((feature) => (
            <div
              key={feature.name}
              className="border border-[rgba(255,255,255,0.08)] bg-[rgba(255,255,255,0.02)] p-6 transition-all hover:border-[rgba(255,255,255,0.15)] hover:bg-[rgba(255,255,255,0.04)] rounded-none group"
            >
              <feature.icon className="h-5 w-5 text-accent transition-transform duration-300 group-hover:scale-110" aria-hidden="true" />
              <p className="mt-3 text-sm font-semibold text-foreground">{feature.name}</p>
            </div>
          ))}
        </div>
      </section>
    </SitePageFrame>
  );
}"

