  { href: "/sentinel?tool=ioc#tools", path: "/sentinel/tools/ioc-lookup", label: "IOC Lookup" },
  { href: "/sentinel?tool=cve#tools", path: "/sentinel/tools/cve-intelligence", label: "CVE Intelligence" },
  { href: "/sentinel?tool=domain#tools", path: "/sentinel/tools/domain-exposure", label: "Domain Exposure Check" },
];

export function SentinelToolTabs() {
  const pathname = usePathname();

  return (
    <div className="flex flex-wrap gap-2">
      {tabs.map((tab) => {
        const isActive = pathname === tab.path;
        return (
          <Link
            key={tab.label}
            href={tab.href}
            className={`inline-flex min-h-10 items-center px-4 text-sm font-medium transition-colors rounded-none ${
              isActive
                ? "border border-[#E72822] bg-[rgba(231,40,34,0.05)] text-foreground"
                : "border border-[rgba(255,255,255,0.08)] bg-[rgba(255,255,255,0.02)] text-muted-foreground hover:bg-[rgba(255,255,255,0.04)] hover:text-foreground"
            }`}
          >
            {tab.label}
          </Link>
        );
      })}
    </div>
  );
}"

