"import * as React from "react";
import { cn } from "../utils/cn";

export type DsTooltipProps = {
  content: React.ReactNode;
  children: React.ReactNode;
  position?: "top" | "bottom" | "left" | "right";
  className?: string;
};

export function DsTooltip({ content, children, position = "top", className }: DsTooltipProps) {
  const [visible, setVisible] = React.useState(false);

  const positionClasses = {
    top: "bottom-full left-1/2 -translate-x-1/2 mb-2",
    bottom: "top-full left-1/2 -translate-x-1/2 mt-2",
    left: "right-full top-1/2 -translate-y-1/2 mr-2",
    right: "left-full top-1/2 -translate-y-1/2 ml-2"
  };

  return (
    <div
      className="relative inline-block"
      onMouseEnter={() => setVisible(true)}
      onMouseLeave={() => setVisible(false)}
      onFocus={() => setVisible(true)}
      onBlur={() => setVisible(false)}
    >
      {children}
      {visible ? (
        <div
          className={cn(
            "absolute z-[100] w-max max-w-xs rounded-none border border-border bg-popover px-3 py-1.5 text-xs text-foreground shadow-lg backdrop-blur-md pointer-events-none font-sans leading-relaxed tracking-wide animate-fade-in",
            positionClasses[position],
            className
          )}
          role="tooltip"
        >
          {content}
        </div>
      ) : null}
    </div>
  );
}
"

